```class Solution {
    public int binaryGap(int n) {
        int maxGap = 0;
        int countZero = 0;
        while (n != 0) {
            int lastZeroIndex = countZero;
            countZero++;
            n >>= 1;
            maxGap = Math.max(maxGap, n - countZero);
        }
        return maxGap;
    }
}
